"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
export default function MarginBudgetField(){const [value,setValue]=useState(16);const reduced=useReducedMotion();const update=(n:number)=>setValue(Math.min(32,Math.max(8,n)));return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><label className="text-xs font-extrabold uppercase tracking-[.14em] text-[#4a4a4f]">Safe margin</label><div className="mt-3 flex items-center gap-3 rounded-2xl bg-[#f4f5f6] p-3"><motion.i aria-hidden className="w-1 rounded-full bg-[#ff9950]" animate={{height:value}} transition={reduced?{duration:0}:{type:"spring",stiffness:320,damping:28}}/><button type="button" aria-label="Decrease margin" disabled={value===8} onClick={()=>update(value-4)} className="min-h-11 min-w-11 rounded-xl border border-[#ececee] bg-white font-black text-[#111] disabled:opacity-40 outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">−</button><output className="flex-1 text-center text-2xl font-black text-[#111]">{value}px</output><button type="button" aria-label="Increase margin" disabled={value===32} onClick={()=>update(value+4)} className="min-h-11 min-w-11 rounded-xl border border-[#ececee] bg-white font-black text-[#111] disabled:opacity-40 outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">+</button></div><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">Safe margin set to {value} pixels.</p></section>}
